# E2-Skeptic three-route assess for S42-T1-A-E2
def assess(record: dict) -> str:
    required = {'json_schema', 'business_rule', 'extra_policy', 'valid_fixture', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (record["extra_policy"] == "allow" and not record["business_rule"])
    except Exception:
        return 'REJECT_SCHEMA'
    return 'PASS' if ok else 'REJECT_SCHEMA'

record = {"case_id": "CASO-CUS-042-1A", **{"extra_policy":"forbid","json_schema":True,"valid_fixture":True,"business_rule":True}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'business_rule'}
print(assess(valid), assess(invalid), assess(incomplete))

